import{_ as s,o as a,c as n,aw as e}from"./chunks/framework.Dq2onT5h.js";const o=JSON.parse('{"title":"Bootstrap a 5-Node HA Cluster from Scratch","description":"","frontmatter":{"head":[["meta",{"name":"og:title","content":"Bootstrap a 5-Node HA Cluster from Scratch | Evolve"},{"name":"og:description","content":false}]]},"headers":[],"relativePath":"guides/ha/cluster-setup.md","filePath":"guides/ha/cluster-setup.md","lastUpdated":1779645806000}');const l=s({name:"guides/ha/cluster-setup.md"},[["render",function(s,o,l,p,t,r){return a(),n("div",null,[...o[0]||(o[0]=[e('<h1 id="bootstrap-a-5-node-ha-cluster-from-scratch" tabindex="-1">Bootstrap a 5-Node HA Cluster from Scratch <a class="header-anchor" href="#bootstrap-a-5-node-ha-cluster-from-scratch" aria-label="Permalink to &quot;Bootstrap a 5-Node HA Cluster from Scratch&quot;">​</a></h1><p>This tutorial walks you through setting up a production-ready 5-node ev-node Raft cluster from zero. By the end you will have five sequencer nodes that automatically elect a leader, replicate block state, and survive individual node failures.</p><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ul><li>Five machines (VMs, bare metal, or containers) with: <ul><li>Network connectivity to each other on the Raft port (we use <code>5001</code>) and P2P port (<code>26656</code>)</li><li>Persistent storage for the Raft data directory</li><li>A working ev-node binary (see the <a href="./../quick-start">quickstart guide</a>)</li></ul></li><li>A private network, VPN, or encrypted mesh between all nodes (Raft transport is plain TCP — never expose the Raft port publicly)</li><li>A shared genesis file for your chain (see <a href="./../create-genesis">Create Genesis</a>)</li><li>A signer key on each node (all nodes must share the same signing identity so block hashes match regardless of which node is the current leader)</li></ul><h3 id="node-addresses-used-in-this-guide" tabindex="-1">Node addresses used in this guide <a class="header-anchor" href="#node-addresses-used-in-this-guide" aria-label="Permalink to &quot;Node addresses used in this guide&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Node</th><th>Private IP</th><th>Raft address</th><th>P2P port</th></tr></thead><tbody><tr><td>node-1</td><td>10.0.0.1</td><td>10.0.0.1:5001</td><td>26656</td></tr><tr><td>node-2</td><td>10.0.0.2</td><td>10.0.0.2:5001</td><td>26656</td></tr><tr><td>node-3</td><td>10.0.0.3</td><td>10.0.0.3:5001</td><td>26656</td></tr><tr><td>node-4</td><td>10.0.0.4</td><td>10.0.0.4:5001</td><td>26656</td></tr><tr><td>node-5</td><td>10.0.0.5</td><td>10.0.0.5:5001</td><td>26656</td></tr></tbody></table><p>Replace these with your actual IP addresses throughout the guide.</p><p>P2P peers use the libp2p multiaddr format, which includes each node&#39;s peer ID:</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span>/ip4/&lt;ip&gt;/tcp/&lt;port&gt;/p2p/&lt;peer-id&gt;</span></span></code></pre></div><p>You will collect peer IDs in Step 3 after initializing each node.</p><hr><h2 id="step-1-measure-network-rtt" tabindex="-1">Step 1: Measure Network RTT <a class="header-anchor" href="#step-1-measure-network-rtt" aria-label="Permalink to &quot;Step 1: Measure Network RTT&quot;">​</a></h2><p>The Raft timing parameters must be sized for your network. Run the following from each node to every other node and note the highest average RTT you observe:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#A0A0A0;"># Example: from node-1, ping all peers</span></span>\n<span class="line"><span style="color:#B8A6FF;">for</span><span style="color:#DBD7CA;"> ip </span><span style="color:#B8A6FF;">in</span><span style="color:#BFF3C2;"> 10.0.0.2</span><span style="color:#BFF3C2;"> 10.0.0.3</span><span style="color:#BFF3C2;"> 10.0.0.4</span><span style="color:#BFF3C2;"> 10.0.0.5</span><span style="color:#767676;">;</span><span style="color:#B8A6FF;"> do</span></span>\n<span class="line"><span style="color:#94EEFF;">  echo</span><span style="color:#FFECB6;"> -n</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">$ip: </span><span style="color:#BFF3C280;">&quot;</span></span>\n<span class="line"><span style="color:#94EEFF;">  ping</span><span style="color:#FFECB6;"> -c</span><span style="color:#FFECB6;"> 20</span><span style="color:#DBD7CA;"> $ip </span><span style="color:#888888;">|</span><span style="color:#94EEFF;"> tail</span><span style="color:#FFECB6;"> -1</span><span style="color:#888888;"> |</span><span style="color:#94EEFF;"> awk</span><span style="color:#FFECB6;"> -F</span><span style="color:#BFF3C280;">&#39;</span><span style="color:#BFF3C2;">/</span><span style="color:#BFF3C280;">&#39;</span><span style="color:#BFF3C280;"> &#39;</span><span style="color:#BFF3C2;">{print $5 &quot;ms avg&quot;}</span><span style="color:#BFF3C280;">&#39;</span></span>\n<span class="line"><span style="color:#B8A6FF;">done</span></span></code></pre></div><p>Repeat from each node. Take the single highest value across all measurements — this is your <code>RTT_MAX</code>.</p><p>For nodes within the same region or data center, <code>RTT_MAX</code> is typically 5–30ms. For the configuration file below we assume <code>RTT_MAX ≤ 25ms</code>. If your measurement is higher, adjust the timing parameters using the formulas in the <a href="./overview#timing-parameters">configuration reference</a>.</p><hr><h2 id="step-2-verify-network-connectivity" tabindex="-1">Step 2: Verify Network Connectivity <a class="header-anchor" href="#step-2-verify-network-connectivity" aria-label="Permalink to &quot;Step 2: Verify Network Connectivity&quot;">​</a></h2><p>Confirm that the Raft port and P2P port are reachable between nodes before starting anything:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#A0A0A0;"># From node-2, verify node-1&#39;s Raft port is reachable</span></span>\n<span class="line"><span style="color:#94EEFF;">nc</span><span style="color:#FFECB6;"> -zv</span><span style="color:#FFECB6;"> 10.0.0.1</span><span style="color:#FFECB6;"> 5001</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#A0A0A0;"># From node-2, verify node-1&#39;s P2P port is reachable</span></span>\n<span class="line"><span style="color:#94EEFF;">nc</span><span style="color:#FFECB6;"> -zv</span><span style="color:#FFECB6;"> 10.0.0.1</span><span style="color:#FFECB6;"> 26656</span></span></code></pre></div><p>Do this for every node pair in both directions. If any check fails, fix your firewall rules before proceeding.</p><hr><h2 id="step-3-initialize-each-node" tabindex="-1">Step 3: Initialize Each Node <a class="header-anchor" href="#step-3-initialize-each-node" aria-label="Permalink to &quot;Step 3: Initialize Each Node&quot;">​</a></h2><p>Run this on every node. Each node gets its own home directory where the config, keys, and data live.</p><p>First, create a passphrase file that only root and the service account can read. This file is referenced by the binary at runtime — the passphrase never appears in process listings or logs.</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#A0A0A0;"># Run on every node</span></span>\n<span class="line"><span style="color:#94EEFF;">sudo</span><span style="color:#BFF3C2;"> mkdir</span><span style="color:#FFECB6;"> -p</span><span style="color:#BFF3C2;"> /etc/ev-node</span></span>\n<span class="line"><span style="color:#94EEFF;">echo</span><span style="color:#FFECB6;"> -n</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">&lt;YOUR_PASSPHRASE&gt;</span><span style="color:#BFF3C280;">&quot;</span><span style="color:#888888;"> |</span><span style="color:#94EEFF;"> sudo</span><span style="color:#BFF3C2;"> tee</span><span style="color:#BFF3C2;"> /etc/ev-node/passphrase</span><span style="color:#888888;"> &gt;</span><span style="color:#BFF3C2;"> /dev/null</span></span>\n<span class="line"><span style="color:#94EEFF;">sudo</span><span style="color:#BFF3C2;"> chmod</span><span style="color:#FFECB6;"> 600</span><span style="color:#BFF3C2;"> /etc/ev-node/passphrase</span></span>\n<span class="line"><span style="color:#94EEFF;">sudo</span><span style="color:#BFF3C2;"> chown</span><span style="color:#BFF3C2;"> ev-node:ev-node</span><span style="color:#BFF3C2;"> /etc/ev-node/passphrase</span></span></code></pre></div><p>Then initialize the node:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#A0A0A0;"># Run on every node (the binary name depends on your chain)</span></span>\n<span class="line"><span style="color:#94EEFF;">./evm</span><span style="color:#BFF3C2;"> init</span><span style="color:#FFECB6;"> --evnode.node.aggregator=true</span><span style="color:#FFECB6;"> --evnode.signer.passphrase_file</span><span style="color:#BFF3C2;"> /etc/ev-node/passphrase</span></span></code></pre></div><p>This creates the home directory structure (default <code>~/.evm</code>) with a <code>config/evnode.yaml</code> file and generates the signer key.</p><p>After initializing each node, retrieve its peer ID — you will need all five when writing the configuration in Step 5:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#A0A0A0;"># Run on each node after init</span></span>\n<span class="line"><span style="color:#94EEFF;">./evm</span><span style="color:#BFF3C2;"> net-info</span></span></code></pre></div><p>Note the <code>peer_id</code> value from each node&#39;s output. It looks like <code>12D3KooW...</code>. You will need all five peer IDs before writing the configuration files.</p><blockquote><p><strong>Shared signer key:</strong> All cluster nodes must sign blocks with the same key so that block hashes produced by any leader are identical. Copy the key material from node-1 to all other nodes after initialization:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#A0A0A0;"># On node-1: locate the signer key</span></span>\n<span class="line"><span style="color:#94EEFF;">ls</span><span style="color:#BFF3C2;"> ~/.evm/config/</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#A0A0A0;"># Secure-copy it to each peer</span></span>\n<span class="line"><span style="color:#94EEFF;">scp</span><span style="color:#BFF3C2;"> ~/.evm/config/signer.json</span><span style="color:#BFF3C2;"> user@10.0.0.2:~/.evm/config/</span></span>\n<span class="line"><span style="color:#94EEFF;">scp</span><span style="color:#BFF3C2;"> ~/.evm/config/signer.json</span><span style="color:#BFF3C2;"> user@10.0.0.3:~/.evm/config/</span></span>\n<span class="line"><span style="color:#94EEFF;">scp</span><span style="color:#BFF3C2;"> ~/.evm/config/signer.json</span><span style="color:#BFF3C2;"> user@10.0.0.4:~/.evm/config/</span></span>\n<span class="line"><span style="color:#94EEFF;">scp</span><span style="color:#BFF3C2;"> ~/.evm/config/signer.json</span><span style="color:#BFF3C2;"> user@10.0.0.5:~/.evm/config/</span></span></code></pre></div></blockquote><hr><h2 id="step-4-distribute-the-genesis-file" tabindex="-1">Step 4: Distribute the Genesis File <a class="header-anchor" href="#step-4-distribute-the-genesis-file" aria-label="Permalink to &quot;Step 4: Distribute the Genesis File&quot;">​</a></h2><p>Every node must start with the same genesis file. Create it on node-1 (see <a href="./../create-genesis">Create Genesis</a>) then copy it to all peers:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">scp</span><span style="color:#BFF3C2;"> ~/.evm/config/genesis.json</span><span style="color:#BFF3C2;"> user@10.0.0.2:~/.evm/config/</span></span>\n<span class="line"><span style="color:#94EEFF;">scp</span><span style="color:#BFF3C2;"> ~/.evm/config/genesis.json</span><span style="color:#BFF3C2;"> user@10.0.0.3:~/.evm/config/</span></span>\n<span class="line"><span style="color:#94EEFF;">scp</span><span style="color:#BFF3C2;"> ~/.evm/config/genesis.json</span><span style="color:#BFF3C2;"> user@10.0.0.4:~/.evm/config/</span></span>\n<span class="line"><span style="color:#94EEFF;">scp</span><span style="color:#BFF3C2;"> ~/.evm/config/genesis.json</span><span style="color:#BFF3C2;"> user@10.0.0.5:~/.evm/config/</span></span></code></pre></div><hr><h2 id="step-5-write-the-configuration-files" tabindex="-1">Step 5: Write the Configuration Files <a class="header-anchor" href="#step-5-write-the-configuration-files" aria-label="Permalink to &quot;Step 5: Write the Configuration Files&quot;">​</a></h2><p>Write the following <code>evnode.yaml</code> on each node. <code>raft.node_id</code> is unique per node; <code>raft.peers</code> and <code>p2p.peers</code> must each exclude the local node — everything else is identical.</p><h3 id="node-1-evm-config-evnode-yaml" tabindex="-1">node-1 (<code>~/.evm/config/evnode.yaml</code>) <a class="header-anchor" href="#node-1-evm-config-evnode-yaml" aria-label="Permalink to &quot;node-1 (`~/.evm/config/evnode.yaml`)&quot;">​</a></h3><div class="language-yaml"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">node</span><span style="color:#767676;">:</span></span>\n<span class="line"><span style="color:#94EEFF;">  aggregator</span><span style="color:#767676;">:</span><span style="color:#FFECB6;"> true</span></span>\n<span class="line"><span style="color:#94EEFF;">  block_time</span><span style="color:#767676;">:</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">1s</span><span style="color:#BFF3C280;">&quot;</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#94EEFF;">raft</span><span style="color:#767676;">:</span></span>\n<span class="line"><span style="color:#94EEFF;">  enable</span><span style="color:#767676;">:</span><span style="color:#FFECB6;"> true</span></span>\n<span class="line"><span style="color:#94EEFF;">  node_id</span><span style="color:#767676;">:</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">node-1</span><span style="color:#BFF3C280;">&quot;</span></span>\n<span class="line"><span style="color:#94EEFF;">  raft_addr</span><span style="color:#767676;">:</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">0.0.0.0:5001</span><span style="color:#BFF3C280;">&quot;</span></span>\n<span class="line"><span style="color:#94EEFF;">  raft_dir</span><span style="color:#767676;">:</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">/var/lib/ev-node/raft</span><span style="color:#BFF3C280;">&quot;</span></span>\n<span class="line"><span style="color:#94EEFF;">  peers</span><span style="color:#767676;">:</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">node-2@10.0.0.2:5001,node-3@10.0.0.3:5001,node-4@10.0.0.4:5001,node-5@10.0.0.5:5001</span><span style="color:#BFF3C280;">&quot;</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#A0A0A0;">  # Timing — tuned for RTT_MAX ≤ 25ms</span></span>\n<span class="line"><span style="color:#94EEFF;">  heartbeat_timeout</span><span style="color:#767676;">:</span><span style="color:#BFF3C280;">    &quot;</span><span style="color:#BFF3C2;">92ms</span><span style="color:#BFF3C280;">&quot;</span></span>\n<span class="line"><span style="color:#94EEFF;">  election_timeout</span><span style="color:#767676;">:</span><span style="color:#BFF3C280;">     &quot;</span><span style="color:#BFF3C2;">368ms</span><span style="color:#BFF3C280;">&quot;</span></span>\n<span class="line"><span style="color:#94EEFF;">  leader_lease_timeout</span><span style="color:#767676;">:</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">46ms</span><span style="color:#BFF3C280;">&quot;</span></span>\n<span class="line"><span style="color:#94EEFF;">  send_timeout</span><span style="color:#767676;">:</span><span style="color:#BFF3C280;">         &quot;</span><span style="color:#BFF3C2;">50ms</span><span style="color:#BFF3C280;">&quot;</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#A0A0A0;">  # Log retention — covers ~5 hours of absence at 1 block/s</span></span>\n<span class="line"><span style="color:#94EEFF;">  trailing_logs</span><span style="color:#767676;">:</span><span style="color:#FFECB6;">      18000</span></span>\n<span class="line"><span style="color:#94EEFF;">  snapshot_threshold</span><span style="color:#767676;">:</span><span style="color:#FFECB6;"> 5000</span></span>\n<span class="line"><span style="color:#94EEFF;">  snap_count</span><span style="color:#767676;">:</span><span style="color:#FFECB6;">         3</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#94EEFF;">p2p</span><span style="color:#767676;">:</span></span>\n<span class="line"><span style="color:#94EEFF;">  listen_address</span><span style="color:#767676;">:</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">/ip4/0.0.0.0/tcp/26656</span><span style="color:#BFF3C280;">&quot;</span></span>\n<span class="line"><span style="color:#94EEFF;">  peers</span><span style="color:#767676;">:</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">/ip4/10.0.0.2/tcp/26656/p2p/&lt;PEER_ID_NODE_2&gt;,/ip4/10.0.0.3/tcp/26656/p2p/&lt;PEER_ID_NODE_3&gt;,/ip4/10.0.0.4/tcp/26656/p2p/&lt;PEER_ID_NODE_4&gt;,/ip4/10.0.0.5/tcp/26656/p2p/&lt;PEER_ID_NODE_5&gt;</span><span style="color:#BFF3C280;">&quot;</span></span></code></pre></div><h3 id="node-2-evm-config-evnode-yaml" tabindex="-1">node-2 (<code>~/.evm/config/evnode.yaml</code>) <a class="header-anchor" href="#node-2-evm-config-evnode-yaml" aria-label="Permalink to &quot;node-2 (`~/.evm/config/evnode.yaml`)&quot;">​</a></h3><p><code>raft.peers</code> must omit the local node. Because <code>raft_addr</code> is <code>0.0.0.0:5001</code> (a wildcard), the self-exclusion check in the bootstrap code compares addresses literally — it will not recognise <code>node-2@10.0.0.2:5001</code> as itself and will add node-2 twice, causing a startup error. Always list only the <strong>other</strong> nodes.</p><div class="language-yaml"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">node</span><span style="color:#767676;">:</span></span>\n<span class="line"><span style="color:#94EEFF;">  aggregator</span><span style="color:#767676;">:</span><span style="color:#FFECB6;"> true</span></span>\n<span class="line"><span style="color:#94EEFF;">  block_time</span><span style="color:#767676;">:</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">1s</span><span style="color:#BFF3C280;">&quot;</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#94EEFF;">raft</span><span style="color:#767676;">:</span></span>\n<span class="line"><span style="color:#94EEFF;">  enable</span><span style="color:#767676;">:</span><span style="color:#FFECB6;"> true</span></span>\n<span class="line"><span style="color:#94EEFF;">  node_id</span><span style="color:#767676;">:</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">node-2</span><span style="color:#BFF3C280;">&quot;</span></span>\n<span class="line"><span style="color:#94EEFF;">  raft_addr</span><span style="color:#767676;">:</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">0.0.0.0:5001</span><span style="color:#BFF3C280;">&quot;</span></span>\n<span class="line"><span style="color:#94EEFF;">  raft_dir</span><span style="color:#767676;">:</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">/var/lib/ev-node/raft</span><span style="color:#BFF3C280;">&quot;</span></span>\n<span class="line"><span style="color:#94EEFF;">  peers</span><span style="color:#767676;">:</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">node-1@10.0.0.1:5001,node-3@10.0.0.3:5001,node-4@10.0.0.4:5001,node-5@10.0.0.5:5001</span><span style="color:#BFF3C280;">&quot;</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#A0A0A0;">  # Timing — tuned for RTT_MAX ≤ 25ms</span></span>\n<span class="line"><span style="color:#94EEFF;">  heartbeat_timeout</span><span style="color:#767676;">:</span><span style="color:#BFF3C280;">    &quot;</span><span style="color:#BFF3C2;">92ms</span><span style="color:#BFF3C280;">&quot;</span></span>\n<span class="line"><span style="color:#94EEFF;">  election_timeout</span><span style="color:#767676;">:</span><span style="color:#BFF3C280;">     &quot;</span><span style="color:#BFF3C2;">368ms</span><span style="color:#BFF3C280;">&quot;</span></span>\n<span class="line"><span style="color:#94EEFF;">  leader_lease_timeout</span><span style="color:#767676;">:</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">46ms</span><span style="color:#BFF3C280;">&quot;</span></span>\n<span class="line"><span style="color:#94EEFF;">  send_timeout</span><span style="color:#767676;">:</span><span style="color:#BFF3C280;">         &quot;</span><span style="color:#BFF3C2;">50ms</span><span style="color:#BFF3C280;">&quot;</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#A0A0A0;">  # Log retention — covers ~5 hours of absence at 1 block/s</span></span>\n<span class="line"><span style="color:#94EEFF;">  trailing_logs</span><span style="color:#767676;">:</span><span style="color:#FFECB6;">      18000</span></span>\n<span class="line"><span style="color:#94EEFF;">  snapshot_threshold</span><span style="color:#767676;">:</span><span style="color:#FFECB6;"> 5000</span></span>\n<span class="line"><span style="color:#94EEFF;">  snap_count</span><span style="color:#767676;">:</span><span style="color:#FFECB6;">         3</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#94EEFF;">p2p</span><span style="color:#767676;">:</span></span>\n<span class="line"><span style="color:#94EEFF;">  listen_address</span><span style="color:#767676;">:</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">/ip4/0.0.0.0/tcp/26656</span><span style="color:#BFF3C280;">&quot;</span></span>\n<span class="line"><span style="color:#94EEFF;">  peers</span><span style="color:#767676;">:</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">/ip4/10.0.0.1/tcp/26656/p2p/&lt;PEER_ID_NODE_1&gt;,/ip4/10.0.0.3/tcp/26656/p2p/&lt;PEER_ID_NODE_3&gt;,/ip4/10.0.0.4/tcp/26656/p2p/&lt;PEER_ID_NODE_4&gt;,/ip4/10.0.0.5/tcp/26656/p2p/&lt;PEER_ID_NODE_5&gt;</span><span style="color:#BFF3C280;">&quot;</span></span></code></pre></div><p>Repeat for node-3 through node-5, updating <code>node_id</code>, <code>raft.peers</code> (exclude the local node), and <code>p2p.peers</code> (exclude the local node).</p><hr><h2 id="step-6-create-the-raft-data-directories" tabindex="-1">Step 6: Create the Raft Data Directories <a class="header-anchor" href="#step-6-create-the-raft-data-directories" aria-label="Permalink to &quot;Step 6: Create the Raft Data Directories&quot;">​</a></h2><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#A0A0A0;"># Run on every node</span></span>\n<span class="line"><span style="color:#94EEFF;">sudo</span><span style="color:#BFF3C2;"> mkdir</span><span style="color:#FFECB6;"> -p</span><span style="color:#BFF3C2;"> /var/lib/ev-node/raft</span></span>\n<span class="line"><span style="color:#94EEFF;">sudo</span><span style="color:#BFF3C2;"> chown</span><span style="color:#767676;"> $(</span><span style="color:#94EEFF;">whoami</span><span style="color:#767676;">)</span><span style="color:#BFF3C2;"> /var/lib/ev-node/raft</span></span></code></pre></div><p>For Docker deployments, this is handled by the named volume — skip this step.</p><hr><h2 id="step-7-start-all-nodes-simultaneously" tabindex="-1">Step 7: Start All Nodes Simultaneously <a class="header-anchor" href="#step-7-start-all-nodes-simultaneously" aria-label="Permalink to &quot;Step 7: Start All Nodes Simultaneously&quot;">​</a></h2><p>Raft requires a majority of configured peers to be online before it can elect a leader. For a 5-node cluster, you need at least 3 nodes to be up before a leader can be elected and blocks can be produced.</p><p>Start all five nodes as close together as possible. The order does not matter but they should all be up within a few seconds of each other.</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#A0A0A0;"># Run this on each node, substituting the correct binary name and flags for your chain</span></span>\n<span class="line"><span style="color:#94EEFF;">./evm</span><span style="color:#BFF3C2;"> start</span><span style="color:#FFECB6;"> \\</span></span>\n<span class="line"><span style="color:#FFECB6;">  --evnode.node.aggregator=true</span><span style="color:#FFECB6;"> \\</span></span>\n<span class="line"><span style="color:#FFECB6;">  --evnode.raft.enable=true</span><span style="color:#FFECB6;"> \\</span></span>\n<span class="line"><span style="color:#FFECB6;">  --evnode.raft.node_id=</span><span style="color:#BFF3C280;">&quot;</span><span style="color:#BFF3C2;">node-1</span><span style="color:#BFF3C280;">&quot;</span><span style="color:#FFECB6;"> \\</span></span>\n<span class="line"><span style="color:#FFECB6;">  --evnode.raft.raft_addr=</span><span style="color:#BFF3C280;">&quot;</span><span style="color:#BFF3C2;">0.0.0.0:5001</span><span style="color:#BFF3C280;">&quot;</span><span style="color:#FFECB6;"> \\</span></span>\n<span class="line"><span style="color:#FFECB6;">  --evnode.raft.raft_dir=</span><span style="color:#BFF3C280;">&quot;</span><span style="color:#BFF3C2;">/var/lib/ev-node/raft</span><span style="color:#BFF3C280;">&quot;</span><span style="color:#FFECB6;"> \\</span></span>\n<span class="line"><span style="color:#FFECB6;">  --evnode.raft.peers=</span><span style="color:#BFF3C280;">&quot;</span><span style="color:#BFF3C2;">node-2@10.0.0.2:5001,node-3@10.0.0.3:5001,node-4@10.0.0.4:5001,node-5@10.0.0.5:5001</span><span style="color:#BFF3C280;">&quot;</span><span style="color:#FFECB6;"> \\</span></span>\n<span class="line"><span style="color:#FFECB6;">  --evnode.raft.heartbeat_timeout=</span><span style="color:#BFF3C280;">&quot;</span><span style="color:#BFF3C2;">92ms</span><span style="color:#BFF3C280;">&quot;</span><span style="color:#FFECB6;"> \\</span></span>\n<span class="line"><span style="color:#FFECB6;">  --evnode.raft.election_timeout=</span><span style="color:#BFF3C280;">&quot;</span><span style="color:#BFF3C2;">368ms</span><span style="color:#BFF3C280;">&quot;</span><span style="color:#FFECB6;"> \\</span></span>\n<span class="line"><span style="color:#FFECB6;">  --evnode.raft.leader_lease_timeout=</span><span style="color:#BFF3C280;">&quot;</span><span style="color:#BFF3C2;">46ms</span><span style="color:#BFF3C280;">&quot;</span><span style="color:#FFECB6;"> \\</span></span>\n<span class="line"><span style="color:#FFECB6;">  --evnode.raft.send_timeout=</span><span style="color:#BFF3C280;">&quot;</span><span style="color:#BFF3C2;">50ms</span><span style="color:#BFF3C280;">&quot;</span><span style="color:#FFECB6;"> \\</span></span>\n<span class="line"><span style="color:#FFECB6;">  --evnode.raft.trailing_logs=18000</span><span style="color:#FFECB6;"> \\</span></span>\n<span class="line"><span style="color:#FFECB6;">  --evnode.raft.snapshot_threshold=5000</span><span style="color:#FFECB6;"> \\</span></span>\n<span class="line"><span style="color:#FFECB6;">  --evnode.raft.snap_count=3</span><span style="color:#FFECB6;"> \\</span></span>\n<span class="line"><span style="color:#FFECB6;">  --evnode.p2p.listen_address=</span><span style="color:#BFF3C280;">&quot;</span><span style="color:#BFF3C2;">/ip4/0.0.0.0/tcp/26656</span><span style="color:#BFF3C280;">&quot;</span><span style="color:#FFECB6;"> \\</span></span>\n<span class="line"><span style="color:#FFECB6;">  --evnode.p2p.peers=</span><span style="color:#BFF3C280;">&quot;</span><span style="color:#BFF3C2;">/ip4/10.0.0.2/tcp/26656/p2p/&lt;PEER_ID_NODE_2&gt;,/ip4/10.0.0.3/tcp/26656/p2p/&lt;PEER_ID_NODE_3&gt;,/ip4/10.0.0.4/tcp/26656/p2p/&lt;PEER_ID_NODE_4&gt;,/ip4/10.0.0.5/tcp/26656/p2p/&lt;PEER_ID_NODE_5&gt;</span><span style="color:#BFF3C280;">&quot;</span><span style="color:#FFECB6;"> \\</span></span>\n<span class="line"><span style="color:#FFECB6;">  --evnode.signer.passphrase_file=/etc/ev-node/passphrase</span><span style="color:#FFECB6;"> \\</span></span>\n<span class="line"><span style="color:#FFECB6;">  --evm.jwt-secret=</span><span style="color:#767676;">$(</span><span style="color:#94EEFF;">cat</span><span style="color:#BFF3C2;"> /path/to/jwt.hex</span><span style="color:#767676;">)</span><span style="color:#FFECB6;"> \\</span></span>\n<span class="line"><span style="color:#FFECB6;">  --evm.genesis-hash=</span><span style="color:#888888;">&lt;</span><span style="color:#FFECB6;">YOUR_GENESIS_HASH</span><span style="color:#888888;">&gt;</span></span></code></pre></div><p>Adjust flags for your execution layer (e.g., remove EVM flags if you are running a Cosmos SDK chain).</p><hr><h2 id="step-8-verify-the-cluster-is-healthy" tabindex="-1">Step 8: Verify the Cluster Is Healthy <a class="header-anchor" href="#step-8-verify-the-cluster-is-healthy" aria-label="Permalink to &quot;Step 8: Verify the Cluster Is Healthy&quot;">​</a></h2><h3 id="watch-the-logs" tabindex="-1">Watch the logs <a class="header-anchor" href="#watch-the-logs" aria-label="Permalink to &quot;Watch the logs&quot;">​</a></h3><p>Within a few seconds of starting, you should see one node win the election:</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span>INF raft: entering candidate state  node=node-1</span></span>\n<span class="line"><span>INF raft: election won               tally=3</span></span>\n<span class="line"><span>INF raft: entering leader state      leader=node-1</span></span>\n<span class="line"><span>INF block produced                   height=1 hash=0xabc...</span></span></code></pre></div><p>The other nodes will log:</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span>INF raft: entering follower state  leader=node-1</span></span>\n<span class="line"><span>INF block applied from raft log    height=1 hash=0xabc...</span></span></code></pre></div><h3 id="check-node-health" tabindex="-1">Check node health <a class="header-anchor" href="#check-node-health" aria-label="Permalink to &quot;Check node health&quot;">​</a></h3><p>Verify each node&#39;s HTTP API is responding:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#A0A0A0;"># ev-node exposes its health endpoint on port 7331 by default</span></span>\n<span class="line"><span style="color:#94EEFF;">curl</span><span style="color:#BFF3C2;"> http://10.0.0.1:7331/health/ready</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#A0A0A0;"># Check which node is the current leader</span></span>\n<span class="line"><span style="color:#94EEFF;">curl</span><span style="color:#BFF3C2;"> http://10.0.0.1:7331/raft/node</span><span style="color:#888888;"> |</span><span style="color:#94EEFF;"> jq</span><span style="color:#BFF3C280;"> &#39;</span><span style="color:#BFF3C2;">{node_id, is_leader}</span><span style="color:#BFF3C280;">&#39;</span></span></code></pre></div><h3 id="check-block-production" tabindex="-1">Check block production <a class="header-anchor" href="#check-block-production" aria-label="Permalink to &quot;Check block production&quot;">​</a></h3><p>For EVM chains, query the execution layer to confirm blocks are being produced:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#A0A0A0;"># Run from any node; the height should increase each time</span></span>\n<span class="line"><span style="color:#94EEFF;">cast</span><span style="color:#BFF3C2;"> block</span><span style="color:#BFF3C2;"> latest</span><span style="color:#FFECB6;"> --rpc-url</span><span style="color:#BFF3C2;"> http://10.0.0.1:8545</span></span></code></pre></div><p>Repeat after a few seconds — the block number should be increasing.</p><h3 id="verify-all-nodes-are-synced" tabindex="-1">Verify all nodes are synced <a class="header-anchor" href="#verify-all-nodes-are-synced" aria-label="Permalink to &quot;Verify all nodes are synced&quot;">​</a></h3><p>Query each node; all five should report the same block height (or within 1–2 blocks of each other):</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#B8A6FF;">for</span><span style="color:#DBD7CA;"> ip </span><span style="color:#B8A6FF;">in</span><span style="color:#BFF3C2;"> 10.0.0.1</span><span style="color:#BFF3C2;"> 10.0.0.2</span><span style="color:#BFF3C2;"> 10.0.0.3</span><span style="color:#BFF3C2;"> 10.0.0.4</span><span style="color:#BFF3C2;"> 10.0.0.5</span><span style="color:#767676;">;</span><span style="color:#B8A6FF;"> do</span></span>\n<span class="line"><span style="color:#94EEFF;">  echo</span><span style="color:#FFECB6;"> -n</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">$ip: height=</span><span style="color:#BFF3C280;">&quot;</span></span>\n<span class="line"><span style="color:#94EEFF;">  cast</span><span style="color:#BFF3C2;"> block</span><span style="color:#BFF3C2;"> latest</span><span style="color:#FFECB6;"> --rpc-url</span><span style="color:#BFF3C2;"> http://</span><span style="color:#DBD7CA;">$ip</span><span style="color:#BFF3C2;">:8545</span><span style="color:#888888;"> |</span><span style="color:#94EEFF;"> jq</span><span style="color:#FFECB6;"> -r</span><span style="color:#BFF3C280;"> &#39;</span><span style="color:#BFF3C2;">.number</span><span style="color:#BFF3C280;">&#39;</span></span>\n<span class="line"><span style="color:#B8A6FF;">done</span></span></code></pre></div><hr><h2 id="step-9-test-failover" tabindex="-1">Step 9: Test Failover <a class="header-anchor" href="#step-9-test-failover" aria-label="Permalink to &quot;Step 9: Test Failover&quot;">​</a></h2><p>With all five nodes running and producing blocks, simulate a leader failure:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#A0A0A0;"># Identify the current leader from its logs, then on that machine.</span></span>\n<span class="line"><span style="color:#A0A0A0;"># Preferred: use the systemd unit if ev-node runs as a service</span></span>\n<span class="line"><span style="color:#94EEFF;">sudo</span><span style="color:#BFF3C2;"> systemctl</span><span style="color:#BFF3C2;"> stop</span><span style="color:#BFF3C2;"> ev-node</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#A0A0A0;"># Fallback: stop the process directly</span></span>\n<span class="line"><span style="color:#94EEFF;">mapfile</span><span style="color:#FFECB6;"> -t</span><span style="color:#BFF3C2;"> PIDS</span><span style="color:#888888;"> &lt;</span><span style="color:#BFF3C280;"> &lt;(</span><span style="color:#94EEFF;">pgrep</span><span style="color:#FFECB6;"> -f</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">evm start</span><span style="color:#BFF3C280;">&quot;)</span></span>\n<span class="line"><span style="color:#B8A6FF;">if</span><span style="color:#767676;"> [</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#767676;">${</span><span style="color:#888888;">#</span><span style="color:#BFF3C2;">PIDS</span><span style="color:#767676;">[</span><span style="color:#888888;">@</span><span style="color:#767676;">]}</span><span style="color:#BFF3C280;">&quot;</span><span style="color:#888888;"> -ne</span><span style="color:#FFECB6;"> 1</span><span style="color:#767676;"> ];</span><span style="color:#B8A6FF;"> then</span></span>\n<span class="line"><span style="color:#94EEFF;">  echo</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">Expected exactly 1 evm PID, found </span><span style="color:#767676;">${</span><span style="color:#888888;">#</span><span style="color:#BFF3C2;">PIDS</span><span style="color:#767676;">[</span><span style="color:#888888;">@</span><span style="color:#767676;">]}</span><span style="color:#BFF3C2;">: </span><span style="color:#767676;">${</span><span style="color:#BFF3C2;">PIDS</span><span style="color:#767676;">[</span><span style="color:#888888;">*</span><span style="color:#767676;">]}</span><span style="color:#BFF3C280;">&quot;</span></span>\n<span class="line"><span style="color:#94EEFF;">  exit</span><span style="color:#FFECB6;"> 1</span></span>\n<span class="line"><span style="color:#B8A6FF;">fi</span></span>\n<span class="line"><span style="color:#94EEFF;">echo</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">Stopping PID </span><span style="color:#767676;">${</span><span style="color:#BFF3C2;">PIDS</span><span style="color:#767676;">[</span><span style="color:#BFF3C2;">0</span><span style="color:#767676;">]}</span><span style="color:#BFF3C280;">&quot;</span></span>\n<span class="line"><span style="color:#94EEFF;">kill</span><span style="color:#FFECB6;"> -SIGTERM</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#767676;">${</span><span style="color:#BFF3C2;">PIDS</span><span style="color:#767676;">[</span><span style="color:#BFF3C2;">0</span><span style="color:#767676;">]}</span><span style="color:#BFF3C280;">&quot;</span></span></code></pre></div><p>Within <code>election_timeout</code> (368ms in this configuration), the remaining four nodes will elect a new leader and resume block production. Measure the actual gap in your logs:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#A0A0A0;"># Look for the last block before the kill and first block after</span></span>\n<span class="line"><span style="color:#94EEFF;">grep</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">block produced\\|block applied</span><span style="color:#BFF3C280;">&quot;</span><span style="color:#BFF3C2;"> /var/log/ev-node/node-2.log</span><span style="color:#888888;"> |</span><span style="color:#94EEFF;"> tail</span><span style="color:#FFECB6;"> -20</span></span></code></pre></div><p>The gap should be well under 1 second in most cases (a few election cycles at most).</p><hr><h2 id="running-as-a-systemd-service" tabindex="-1">Running as a Systemd Service <a class="header-anchor" href="#running-as-a-systemd-service" aria-label="Permalink to &quot;Running as a Systemd Service&quot;">​</a></h2><p>For production, manage each node with systemd.</p><h3 id="create-the-passphrase-file" tabindex="-1">Create the passphrase file <a class="header-anchor" href="#create-the-passphrase-file" aria-label="Permalink to &quot;Create the passphrase file&quot;">​</a></h3><p>If you did not create the passphrase file in Step 3, do it now. The file must exist on every node before the service starts:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#A0A0A0;"># Run on every node (skip if you already did this in Step 3)</span></span>\n<span class="line"><span style="color:#94EEFF;">sudo</span><span style="color:#BFF3C2;"> mkdir</span><span style="color:#FFECB6;"> -p</span><span style="color:#BFF3C2;"> /etc/ev-node</span></span>\n<span class="line"><span style="color:#94EEFF;">echo</span><span style="color:#FFECB6;"> -n</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">&lt;YOUR_PASSPHRASE&gt;</span><span style="color:#BFF3C280;">&quot;</span><span style="color:#888888;"> |</span><span style="color:#94EEFF;"> sudo</span><span style="color:#BFF3C2;"> tee</span><span style="color:#BFF3C2;"> /etc/ev-node/passphrase</span><span style="color:#888888;"> &gt;</span><span style="color:#BFF3C2;"> /dev/null</span></span>\n<span class="line"><span style="color:#94EEFF;">sudo</span><span style="color:#BFF3C2;"> chmod</span><span style="color:#FFECB6;"> 600</span><span style="color:#BFF3C2;"> /etc/ev-node/passphrase</span></span>\n<span class="line"><span style="color:#94EEFF;">sudo</span><span style="color:#BFF3C2;"> chown</span><span style="color:#BFF3C2;"> ev-node:ev-node</span><span style="color:#BFF3C2;"> /etc/ev-node/passphrase</span></span></code></pre></div><h3 id="unit-file" tabindex="-1">Unit file <a class="header-anchor" href="#unit-file" aria-label="Permalink to &quot;Unit file&quot;">​</a></h3><div class="language-ini"><button title="Copy Code" class="copy"></button><span class="lang">ini</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#A0A0A0;"># /etc/systemd/system/ev-node.service</span></span>\n<span class="line"><span style="color:#767676;">[</span><span style="color:#94EEFF;">Unit</span><span style="color:#767676;">]</span></span>\n<span class="line"><span style="color:#B8A6FF;">Description</span><span style="color:#767676;">=</span><span style="color:#DBD7CA;">ev-node HA sequencer</span></span>\n<span class="line"><span style="color:#B8A6FF;">After</span><span style="color:#767676;">=</span><span style="color:#DBD7CA;">network-online.target</span></span>\n<span class="line"><span style="color:#B8A6FF;">Wants</span><span style="color:#767676;">=</span><span style="color:#DBD7CA;">network-online.target</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#767676;">[</span><span style="color:#94EEFF;">Service</span><span style="color:#767676;">]</span></span>\n<span class="line"><span style="color:#B8A6FF;">User</span><span style="color:#767676;">=</span><span style="color:#DBD7CA;">ev-node</span></span>\n<span class="line"><span style="color:#B8A6FF;">ExecStart</span><span style="color:#767676;">=</span><span style="color:#DBD7CA;">/usr/local/bin/evm start \\</span></span>\n<span class="line"><span style="color:#DBD7CA;">  --</span><span style="color:#B8A6FF;">evnode.node.aggregator</span><span style="color:#767676;">=</span><span style="color:#DBD7CA;">true \\</span></span>\n<span class="line"><span style="color:#DBD7CA;">  --</span><span style="color:#B8A6FF;">evnode.raft.enable</span><span style="color:#767676;">=</span><span style="color:#DBD7CA;">true \\</span></span>\n<span class="line"><span style="color:#DBD7CA;">  --</span><span style="color:#B8A6FF;">evnode.raft.node_id</span><span style="color:#767676;">=</span><span style="color:#DBD7CA;">node-1 \\</span></span>\n<span class="line"><span style="color:#DBD7CA;">  --</span><span style="color:#B8A6FF;">evnode.raft.raft_addr</span><span style="color:#767676;">=</span><span style="color:#DBD7CA;">0.0.0.0:5001 \\</span></span>\n<span class="line"><span style="color:#DBD7CA;">  --</span><span style="color:#B8A6FF;">evnode.raft.raft_dir</span><span style="color:#767676;">=</span><span style="color:#DBD7CA;">/var/lib/ev-node/raft \\</span></span>\n<span class="line"><span style="color:#DBD7CA;">  --</span><span style="color:#B8A6FF;">evnode.raft.peers</span><span style="color:#767676;">=</span><span style="color:#DBD7CA;">node-2@10.0.0.2:5001,node-3@10.0.0.3:5001,node-4@10.0.0.4:5001,node-5@10.0.0.5:5001 \\</span></span>\n<span class="line"><span style="color:#DBD7CA;">  --</span><span style="color:#B8A6FF;">evnode.raft.heartbeat_timeout</span><span style="color:#767676;">=</span><span style="color:#DBD7CA;">92ms \\</span></span>\n<span class="line"><span style="color:#DBD7CA;">  --</span><span style="color:#B8A6FF;">evnode.raft.election_timeout</span><span style="color:#767676;">=</span><span style="color:#DBD7CA;">368ms \\</span></span>\n<span class="line"><span style="color:#DBD7CA;">  --</span><span style="color:#B8A6FF;">evnode.raft.leader_lease_timeout</span><span style="color:#767676;">=</span><span style="color:#DBD7CA;">46ms \\</span></span>\n<span class="line"><span style="color:#DBD7CA;">  --</span><span style="color:#B8A6FF;">evnode.raft.send_timeout</span><span style="color:#767676;">=</span><span style="color:#DBD7CA;">50ms \\</span></span>\n<span class="line"><span style="color:#DBD7CA;">  --</span><span style="color:#B8A6FF;">evnode.raft.trailing_logs</span><span style="color:#767676;">=</span><span style="color:#DBD7CA;">18000 \\</span></span>\n<span class="line"><span style="color:#DBD7CA;">  --</span><span style="color:#B8A6FF;">evnode.raft.snapshot_threshold</span><span style="color:#767676;">=</span><span style="color:#DBD7CA;">5000 \\</span></span>\n<span class="line"><span style="color:#DBD7CA;">  --</span><span style="color:#B8A6FF;">evnode.p2p.listen_address</span><span style="color:#767676;">=</span><span style="color:#DBD7CA;">/ip4/0.0.0.0/tcp/26656 \\</span></span>\n<span class="line"><span style="color:#DBD7CA;">  --</span><span style="color:#B8A6FF;">evnode.p2p.peers</span><span style="color:#767676;">=</span><span style="color:#DBD7CA;">/ip4/10.0.0.2/tcp/26656/p2p/&lt;PEER_ID_NODE_2&gt;,/ip4/10.0.0.3/tcp/26656/p2p/&lt;PEER_ID_NODE_3&gt;,/ip4/10.0.0.4/tcp/26656/p2p/&lt;PEER_ID_NODE_4&gt;,/ip4/10.0.0.5/tcp/26656/p2p/&lt;PEER_ID_NODE_5&gt; \\</span></span>\n<span class="line"><span style="color:#DBD7CA;">  --</span><span style="color:#B8A6FF;">evnode.signer.passphrase_file</span><span style="color:#767676;">=</span><span style="color:#DBD7CA;">/etc/ev-node/passphrase</span></span>\n<span class="line"><span style="color:#B8A6FF;">Restart</span><span style="color:#767676;">=</span><span style="color:#DBD7CA;">on-failure</span></span>\n<span class="line"><span style="color:#B8A6FF;">RestartSec</span><span style="color:#767676;">=</span><span style="color:#DBD7CA;">5s</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#A0A0A0;"># Give the process time to transfer leadership before systemd kills it</span></span>\n<span class="line"><span style="color:#B8A6FF;">TimeoutStopSec</span><span style="color:#767676;">=</span><span style="color:#DBD7CA;">30</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#767676;">[</span><span style="color:#94EEFF;">Install</span><span style="color:#767676;">]</span></span>\n<span class="line"><span style="color:#B8A6FF;">WantedBy</span><span style="color:#767676;">=</span><span style="color:#DBD7CA;">multi-user.target</span></span></code></pre></div><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">sudo</span><span style="color:#BFF3C2;"> systemctl</span><span style="color:#BFF3C2;"> daemon-reload</span></span>\n<span class="line"><span style="color:#94EEFF;">sudo</span><span style="color:#BFF3C2;"> systemctl</span><span style="color:#BFF3C2;"> enable</span><span style="color:#BFF3C2;"> ev-node</span></span>\n<span class="line"><span style="color:#94EEFF;">sudo</span><span style="color:#BFF3C2;"> systemctl</span><span style="color:#BFF3C2;"> start</span><span style="color:#BFF3C2;"> ev-node</span></span>\n<span class="line"><span style="color:#94EEFF;">sudo</span><span style="color:#BFF3C2;"> journalctl</span><span style="color:#FFECB6;"> -u</span><span style="color:#BFF3C2;"> ev-node</span><span style="color:#FFECB6;"> -f</span></span></code></pre></div><p><code>TimeoutStopSec=30</code> gives the node enough time to perform a graceful leadership transfer on <code>SIGTERM</code> before systemd sends <code>SIGKILL</code>. Do not set this too short.</p><hr><h2 id="performing-a-rolling-restart" tabindex="-1">Performing a Rolling Restart <a class="header-anchor" href="#performing-a-rolling-restart" aria-label="Permalink to &quot;Performing a Rolling Restart&quot;">​</a></h2><p>To restart nodes without taking the cluster offline (e.g., for a config change or binary upgrade):</p><ol><li>Restart one non-leader node at a time and wait for it to rejoin before touching the next.</li><li>For the leader node, restart it last. <code>ev-node</code> will transfer leadership to a peer before shutting down.</li></ol><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#A0A0A0;"># Restart non-leader nodes first, one at a time.</span></span>\n<span class="line"><span style="color:#A0A0A0;"># After each restart, wait until the node confirms it has rejoined before touching the next.</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#94EEFF;">ssh</span><span style="color:#BFF3C2;"> user@10.0.0.2</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">sudo systemctl restart ev-node</span><span style="color:#BFF3C280;">&quot;</span></span>\n<span class="line"><span style="color:#94EEFF;">ssh</span><span style="color:#BFF3C2;"> user@10.0.0.2</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">sudo journalctl -u ev-node --since &#39;1 min ago&#39; -f | grep -m1 &#39;follower state\\|leader state&#39;</span><span style="color:#BFF3C280;">&quot;</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#94EEFF;">ssh</span><span style="color:#BFF3C2;"> user@10.0.0.3</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">sudo systemctl restart ev-node</span><span style="color:#BFF3C280;">&quot;</span></span>\n<span class="line"><span style="color:#94EEFF;">ssh</span><span style="color:#BFF3C2;"> user@10.0.0.3</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">sudo journalctl -u ev-node --since &#39;1 min ago&#39; -f | grep -m1 &#39;follower state\\|leader state&#39;</span><span style="color:#BFF3C280;">&quot;</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#94EEFF;">ssh</span><span style="color:#BFF3C2;"> user@10.0.0.4</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">sudo systemctl restart ev-node</span><span style="color:#BFF3C280;">&quot;</span></span>\n<span class="line"><span style="color:#94EEFF;">ssh</span><span style="color:#BFF3C2;"> user@10.0.0.4</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">sudo journalctl -u ev-node --since &#39;1 min ago&#39; -f | grep -m1 &#39;follower state\\|leader state&#39;</span><span style="color:#BFF3C280;">&quot;</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#94EEFF;">ssh</span><span style="color:#BFF3C2;"> user@10.0.0.5</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">sudo systemctl restart ev-node</span><span style="color:#BFF3C280;">&quot;</span></span>\n<span class="line"><span style="color:#94EEFF;">ssh</span><span style="color:#BFF3C2;"> user@10.0.0.5</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">sudo journalctl -u ev-node --since &#39;1 min ago&#39; -f | grep -m1 &#39;follower state\\|leader state&#39;</span><span style="color:#BFF3C280;">&quot;</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#A0A0A0;"># Restart the leader last — ev-node transfers leadership before shutting down</span></span>\n<span class="line"><span style="color:#94EEFF;">ssh</span><span style="color:#BFF3C2;"> user@10.0.0.1</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">sudo systemctl restart ev-node</span><span style="color:#BFF3C280;">&quot;</span></span>\n<span class="line"><span style="color:#94EEFF;">ssh</span><span style="color:#BFF3C2;"> user@10.0.0.1</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">sudo journalctl -u ev-node --since &#39;1 min ago&#39; -f | grep -m1 &#39;follower state\\|leader state&#39;</span><span style="color:#BFF3C280;">&quot;</span></span></code></pre></div><p>The <code>grep -m1</code> exits as soon as the node logs <code>entering follower state</code> or <code>entering leader state</code>, confirming it has rejoined the cluster. Only then proceed to the next node.</p><hr><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><h3 id="cluster-does-not-elect-a-leader" tabindex="-1">Cluster does not elect a leader <a class="header-anchor" href="#cluster-does-not-elect-a-leader" aria-label="Permalink to &quot;Cluster does not elect a leader&quot;">​</a></h3><p>Check that:</p><ul><li>At least 3 out of 5 nodes are running and can reach each other on port 5001.</li><li>The <code>peers</code> list on every node is identical and all addresses are correct.</li><li>No firewall rule is blocking TCP on port 5001.</li></ul><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#A0A0A0;"># Quick connectivity check from node-2 to node-1 Raft port</span></span>\n<span class="line"><span style="color:#94EEFF;">nc</span><span style="color:#FFECB6;"> -zv</span><span style="color:#FFECB6;"> 10.0.0.1</span><span style="color:#FFECB6;"> 5001</span></span></code></pre></div><h3 id="node-panics-on-startup-with-state-divergence" tabindex="-1">Node panics on startup with &quot;state divergence&quot; <a class="header-anchor" href="#node-panics-on-startup-with-state-divergence" aria-label="Permalink to &quot;Node panics on startup with &quot;state divergence&quot;&quot;">​</a></h3><p>This means the node&#39;s local block store is ahead of or behind the Raft consensus state in a way that cannot be reconciled automatically. This typically happens when a node&#39;s <code>raft_dir</code> was wiped but the block database was not (or vice versa).</p><p>Stop the node, wipe both <code>raft_dir</code> and the node&#39;s block data directory, then restart. The node will receive a Raft snapshot and rebuild from there.</p><h3 id="spurious-elections-leadership-flapping" tabindex="-1">Spurious elections / leadership flapping <a class="header-anchor" href="#spurious-elections-leadership-flapping" aria-label="Permalink to &quot;Spurious elections / leadership flapping&quot;">​</a></h3><p>Symptoms: frequent <code>election won</code> and <code>entering follower state</code> lines in the logs, block production pausing briefly every few seconds.</p><p>Causes:</p><ul><li><code>heartbeat_timeout</code> is too short for your network RTT — increase it.</li><li>Network congestion or packet loss between nodes.</li><li>Node CPU is saturated and cannot process heartbeats in time.</li></ul><p>As a quick diagnostic, check the RTT between nodes while the cluster is running:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">ping</span><span style="color:#FFECB6;"> -c</span><span style="color:#FFECB6;"> 100</span><span style="color:#FFECB6;"> 10.0.0.2</span><span style="color:#888888;"> |</span><span style="color:#94EEFF;"> tail</span><span style="color:#FFECB6;"> -5</span></span></code></pre></div><p>If the max RTT is close to or above <code>heartbeat_timeout</code>, increase <code>heartbeat_timeout</code> and <code>election_timeout</code> proportionally.</p>',112)])])}]]);export{o as __pageData,l as default};
